previewCss:
.darma-loader-cssloaders-github-14 {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 4px;
      height: 44px;
    }
    .darma-loader-cssloaders-github-14 i {
      display: block;
      width: 7px;
      height: 44px;
      border-radius: 999px;
      background: linear-gradient(180deg, var(--loader-color), var(--loader-secondary-color));
      transform-origin: center bottom;
      animation: darma-loader-cssloaders-github-14-barPulse 1.05s ease-in-out infinite;
    }
    .darma-loader-cssloaders-github-14 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-cssloaders-github-14 i:nth-child(2) { animation-delay: 0.09s; }
.darma-loader-cssloaders-github-14 i:nth-child(3) { animation-delay: 0.18s; }
.darma-loader-cssloaders-github-14 i:nth-child(4) { animation-delay: 0.27s; }
.darma-loader-cssloaders-github-14 i:nth-child(5) { animation-delay: 0.36s; }
    @keyframes darma-loader-cssloaders-github-14-barPulse { 0%, 100% { opacity: .25; transform: scaleY(.5); } 45% { opacity: 1; transform: scaleY(1); } }

